import ReportBiUpdateView from './components/views/ReportBiUpdateView';
import type { ViewType } from './types';

declare const lucide: any;

export default function App() {
    const [currentView, setCurrentView] = useState<ViewType>('dashboard');
    // Change default state to true (collapsed) for hover UI
    const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    useEffect(() => {
        if (typeof lucide !== 'undefined' && lucide) {
            lucide.createIcons();
        }
    }, [currentView, isSidebarCollapsed]);

    const renderView = () => {
        switch (currentView) {
            case 'dashboard':
                return <DashboardView />;
            case 'tax':
                return <TaxCalculatorView />;
            case 'coupon':
                return <CouponConverterView />;
            case 'efficiency':
                return <EmployeeEfficiencyView />;
            case 'checklist':
                return <DailyChecklistReportView />;
            case 'bi_update':
                return <ReportBiUpdateView />;
            default:
                return <DashboardView />;
        }
    };

    return (
        <div className="flex min-h-screen bg-slate-50 dark:bg-slate-900 transition-colors duration-500 overflow-hidden">
            {/* Sidebar Navigation */}
            <Sidebar 
                currentView={currentView} 
                setCurrentView={setCurrentView}
                isCollapsed={isSidebarCollapsed}
                setIsCollapsed={setIsSidebarCollapsed}
                isMobileOpen={isMobileMenuOpen}
                setIsMobileOpen={setIsMobileMenuOpen}
            />

            {/* Main Application Area */}
            <main className={`flex-grow overflow-y-auto transition-all duration-300 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'}`}>
                {/* Mobile Header (Hidden on Desktop) */}
                <div className="md:hidden flex items-center justify-between p-4 bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700 sticky top-0 z-30">
                    <div className="flex items-center gap-2">
                        <div className="p-1.5 bg-indigo-600 rounded-lg text-white">
                            <i data-lucide="zap" className="w-5 h-5"></i>
                        </div>
                        <span className="font-black text-slate-800 dark:text-white tracking-tight uppercase">HUB 2.0</span>
                    </div>
                    <button 
                        onClick={() => setIsMobileMenuOpen(true)}
                        className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg"
                    >
                        <i data-lucide="menu" className="w-6 h-6"></i>
                    </button>
                </div>

                <div className="w-full">
                    {renderView()}
                </div>
            </main>

            {/* Overlay for mobile sidebar */}
            {isMobileMenuOpen && (
                <div 
                    className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[90] md:hidden"
                    onClick={() => setIsMobileMenuOpen(false)}
                ></div>
            )}
        </div>
    );
}

import React, { useRef } from 'react';
import { Icon } from '../common/Icon';
import type { ViewType } from '../../types';

interface SidebarProps {
    currentView: ViewType;
    setCurrentView: (view: ViewType) => void;
    isCollapsed: boolean;
    setIsCollapsed: (collapsed: boolean) => void;
    isMobileOpen: boolean;
    setIsMobileOpen: (open: boolean) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    currentView, 
    setCurrentView, 
    isCollapsed, 
    setIsCollapsed,
    isMobileOpen,
    setIsMobileOpen
}) => {
    const timerRef = useRef<any>(null);

    const menuItems: { id: ViewType; label: string; icon: string; color: string }[] = [
        { id: 'dashboard', label: 'Báo Cáo YCX', icon: 'layout-dashboard', color: 'indigo' },
        { id: 'bi_update', label: 'Cập nhật BI', icon: 'refresh-cw', color: 'sky' },
        { id: 'tax', label: 'Tính Thuế TNCN', icon: 'calculator', color: 'rose' },
        { id: 'coupon', label: 'Đổi Coupon', icon: 'ticket', color: 'amber' },
        { id: 'efficiency', label: 'Thi Đua & Hiệu Suất', icon: 'trending-up', color: 'emerald' },
        { id: 'checklist', label: 'Daily Checklist', icon: 'clipboard-check', color: 'violet' }
    ];

    const handleMenuClick = (id: ViewType) => {
        setCurrentView(id);
        setIsMobileOpen(false);
    };

    // Hover Handlers with Debounce
    const handleMouseEnter = () => {
        if (window.innerWidth >= 768) { // Only on Desktop
            if (timerRef.current) clearTimeout(timerRef.current);
            setIsCollapsed(false);
        }
    };

    const handleMouseLeave = () => {
        if (window.innerWidth >= 768) {
            // Add slight delay to prevent flickering
            timerRef.current = setTimeout(() => {
                setIsCollapsed(true);
            }, 300);
        }
    };

    return (
        <aside 
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            className={`fixed left-0 top-0 h-full z-[100] transition-all duration-300 ease-in-out border-r border-slate-200 dark:border-slate-800 bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl flex flex-col shadow-2xl
                ${isMobileOpen ? 'translate-x-0 w-72' : '-translate-x-full md:translate-x-0'}
                ${isCollapsed ? 'md:w-20' : 'md:w-64'}
            `}
        >
            {/* Header / Logo */}
            <div className={`flex items-center gap-3 p-6 mb-4 ${isCollapsed ? 'justify-center' : ''}`}>
                <div className="shrink-0 p-2.5 bg-indigo-600 text-white rounded-2xl shadow-lg shadow-indigo-200 dark:shadow-none">
                    <Icon name="zap" size={6} />
                </div>
                {(!isCollapsed || isMobileOpen) && (
                    <div className="overflow-hidden whitespace-nowrap">
                        <h2 className="text-xl font-black text-slate-800 dark:text-white tracking-tighter">HUB <span className="text-indigo-600">2.0</span></h2>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">BI Analyst</p>
                    </div>
                )}
            </div>

            {/* Navigation Menu */}
            <nav className="flex-grow px-3 space-y-1.5 overflow-y-auto custom-scrollbar overflow-x-hidden">
                {menuItems.map((item) => (
                    <button 
                        key={item.id}
                        onClick={() => handleMenuClick(item.id)}
                        className={`w-full flex items-center gap-4 p-3.5 rounded-2xl transition-all duration-200 group relative
                            ${currentView === item.id 
                                ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100 dark:shadow-none font-bold' 
                                : 'text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 hover:text-indigo-600 font-medium'
                            }
                        `}
                    >
                        <div className={`shrink-0 transition-colors ${currentView === item.id ? 'text-white' : `text-${item.color}-500`}`}>
                            <Icon name={item.icon} size={5} />
                        </div>

                        {(!isCollapsed || isMobileOpen) && (
                            <span className="text-sm whitespace-nowrap overflow-hidden">{item.label}</span>
                        )}

                        {currentView === item.id && !isCollapsed && (
                            <div className="absolute right-3 w-1.5 h-1.5 rounded-full bg-white opacity-60"></div>
                        )}

                        {/* Tooltip for collapsed view */}
                        {isCollapsed && !isMobileOpen && (
                            <div className="absolute left-full ml-4 px-3 py-2 bg-slate-800 text-white text-xs rounded-lg opacity-0 group-hover:opacity-100 pointer-events-none transition-opacity whitespace-nowrap z-50 shadow-xl font-bold">
                                {item.label}
                                <div className="absolute left-0 top-1/2 -translate-x-1/2 -translate-y-1/2 border-8 border-transparent border-r-slate-800"></div>
                            </div>
                        )}
                    </button>
                ))}
            </nav>

            {/* Footer Profile - No Toggle Button */}
            <div className="p-4 space-y-4 border-t border-slate-100 dark:border-slate-800 mt-auto overflow-hidden">
                <div className={`flex items-center gap-3 ${isCollapsed ? 'justify-center' : 'px-3 py-2'}`}>
                    <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shrink-0 flex items-center justify-center text-slate-400">
                        <Icon name="user" size={5} />
                    </div>
                    {(!isCollapsed || isMobileOpen) && (
                        <div className="overflow-hidden whitespace-nowrap">
                            <p className="text-xs font-black text-slate-800 dark:text-white uppercase truncate">Admin Hub</p>
                            <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Bi Analyst 2025</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Mobile Close Button */}
            {isMobileOpen && (
                <button 
                    onClick={() => setIsMobileOpen(false)}
                    className="absolute top-4 right-4 md:hidden p-2 text-slate-400 hover:text-slate-800"
                >
                    <Icon name="x" size={6} />
                </button>
            )}
        </aside>
    );
};

export default Sidebar;

